/** Short label for sidebar component tiles: one word when possible, no overflow. */
function getShortLibraryLabel(sectionKey: string, displayLabel: string): string {
    const def = getComponent(sectionKey);
    if (def?.name) {
        const words = def.name.trim().split(/\s+/);
        return words.length > 1 ? words[0]! : def.name;
    }
    if (displayLabel.length <= 12) return displayLabel;
    return displayLabel.slice(0, 10).trim() + '…';
}

