function buildGeneralFoundationResponsiveStyleOverrideSchema(breakpointLabel: 'Desktop' | 'Tablet' | 'Mobile'): Record<string, unknown> {
    return {
        type: 'object',
        properties: {
            bg_color: { type: 'string', title: `Responsive: ${breakpointLabel} Background Override`, default: '' },
            overlay_color: { type: 'string', title: `Responsive: ${breakpointLabel} Overlay Color Override`, default: '' },
            overlay_opacity_percent: { type: 'integer', title: `Responsive: ${breakpointLabel} Overlay Opacity (%)`, default: null },
            fg_color: { type: 'string', title: `Responsive: ${breakpointLabel} Text Color Override`, default: '' },
            bd_color: { type: 'string', title: `Responsive: ${breakpointLabel} Border Color Override`, default: '' },
            border_radius_px: { type: 'integer', title: `Responsive: ${breakpointLabel} Border Radius (px)`, default: null },
            padding_y_px: { type: 'integer', title: `Responsive: ${breakpointLabel} Vertical Padding (px)`, default: null },
            padding_x_px: { type: 'integer', title: `Responsive: ${breakpointLabel} Horizontal Padding (px)`, default: null },
            margin_y_px: { type: 'integer', title: `Responsive: ${breakpointLabel} Vertical Margin (px)`, default: null },
        },
    };
}

function buildGeneralFoundationStateStyleOverrideSchema(stateLabel: 'Normal' | 'Hover' | 'Focus' | 'Active'): Record<string, unknown> {
    return {
        type: 'object',
        properties: {
            bg_color: { type: 'string', title: `State: ${stateLabel} Background Override`, default: '' },
            overlay_color: { type: 'string', title: `State: ${stateLabel} Overlay Color Override`, default: '' },
            overlay_opacity_percent: { type: 'integer', title: `State: ${stateLabel} Overlay Opacity (%)`, default: null },
            fg_color: { type: 'string', title: `State: ${stateLabel} Text Color Override`, default: '' },
            bd_color: { type: 'string', title: `State: ${stateLabel} Border Color Override`, default: '' },
            border_radius_px: { type: 'integer', title: `State: ${stateLabel} Border Radius (px)`, default: null },
            padding_y_px: { type: 'integer', title: `State: ${stateLabel} Vertical Padding (px)`, default: null },
            padding_x_px: { type: 'integer', title: `State: ${stateLabel} Horizontal Padding (px)`, default: null },
            margin_y_px: { type: 'integer', title: `State: ${stateLabel} Vertical Margin (px)`, default: null },
        },
    };
}

