function buildGeneralFoundationBaselineSchema(): Record<string, unknown> {
    return cloneJsonValue(GENERAL_FOUNDATION_BASELINE_SCHEMA_PROPERTIES) as Record<string, unknown>;
}

function augmentGeneralSectionSchemaWithFoundationBaseline(schema: Record<string, unknown> | null): Record<string, unknown> | null {
    if (!schema || !isRecord(schema)) {
        return schema;
    }

    const nextSchema = cloneJsonValue(schema);
    if (!isRecord(nextSchema)) {
        return schema;
    }

    const properties = isRecord(nextSchema.properties) ? { ...nextSchema.properties } : {};
    const baseline = buildGeneralFoundationBaselineSchema();

    Object.entries(baseline).forEach(([key, value]) => {
        if (properties[key] === undefined) {
            properties[key] = value;
        }
    });

    nextSchema.properties = properties;
    return nextSchema;
}

