    const sectionSchemaByKey = useMemo(() => {
        const map = new Map<string, Record<string, unknown>>();
        builderSectionLibrary.forEach((item) => {
            const normalizedKey = normalizeSectionTypeKey(item.key);
            const schema = isGeneralSectionKey(normalizedKey)
                ? augmentGeneralSectionSchemaWithFoundationBaseline(item.schema_json) ?? item.schema_json
                : item.schema_json;

            map.set(item.key, schema);
            map.set(normalizedKey, schema);
        });
        // Runtime wiring: ensure sidebar has schema for every registry component, even if not in server library.
        // So when a section on the page has type X, the sidebar can generate controls from registry schema.
        getAvailableComponents().forEach((registryId) => {
            const normalized = normalizeSectionTypeKey(registryId);
            if (normalized === '' || map.has(normalized)) return;
            const schemaJson = getComponentSchemaJson(registryId) ?? getComponentSchemaJson(normalized);
            if (isRecord(schemaJson) && Object.keys(schemaJson).length > 0) {
                map.set(registryId, schemaJson);
                map.set(normalized, schemaJson);
            }
        });
        return map;
    }, [builderSectionLibrary]);
    const templateSectionsBySlug = useMemo(() => {
        const raw = isRecord(templateBlueprint?.default_sections) ? templateBlueprint.default_sections : {};
        const map = new Map<string, Array<{ type: string; props: Record<string, unknown> }>>();

        Object.entries(raw).forEach(([slug, sectionBlueprints]) => {
            const normalizedSlug = slug.trim().toLowerCase().replace(/^\/+|\/+$/g, '');
            const resolvedSlug = normalizedSlug === '' || normalizedSlug === 'index'
                ? 'home'
                : normalizedSlug;
            map.set(resolvedSlug, normalizeTemplateSectionBlueprints(sectionBlueprints));
        });

        CANONICAL_STOREFRONT_PAGE_TEMPLATE_PRESETS.forEach((preset) => {
            const variants = [preset.slug, ...(preset.aliases ?? [])]
                .map((value) => value.trim().toLowerCase().replace(/^\/+|\/+$/g, ''))
                .filter((value, index, list) => value !== '' && list.indexOf(value) === index)
                .map((value) => (value === 'index' ? 'home' : value));

            variants.forEach((variantSlug) => {
                const existing = map.get(variantSlug);
                if (Array.isArray(existing) && existing.length > 0) {
                    return;
                }

                map.set(
                    variantSlug,
                    preset.section_blueprints.map((section) => ({
                        type: section.type,
                        props: cloneRecord(section.props),
                    }))
                );
            });
        });

        return map;
    }, [templateBlueprint]);
    const canUseEcommercePageTemplates = useMemo(() => (
        isAdminUser || modules.some((module) => module.key === MODULE_ECOMMERCE && module.available)
    ), [isAdminUser, modules]);
