    const emitCmsBuilderTelemetry = useCallback((
        eventName: string,
        options?: {
            pageId?: number | null;
            pageSlug?: string | null;
            meta?: Record<string, unknown>;
        },
    ) => {
        const trimmedEventName = eventName.trim();
        if (trimmedEventName === '') {
            return;
        }

        const routePath = typeof window !== 'undefined'
            ? window.location.pathname
            : page.url;

        void axios.post(`/panel/sites/${site.id}/cms/telemetry`, {
            schema_version: 'cms.telemetry.event.v1',
            source: 'builder',
            session_id: builderTelemetrySessionIdRef.current,
            route: {
                path: routePath,
                slug: options?.pageSlug ?? null,
                params: {},
            },
            context: {
                surface: 'cms_builder',
                section: activeSection,
                tab: activeTab,
                editor_mode: pageEditorMode,
                preview_mode: builderPreviewMode,
            },
            events: [
                {
                    name: trimmedEventName,
                    at: new Date().toISOString(),
                    page_id: options?.pageId ?? null,
                    page_slug: options?.pageSlug ?? null,
                    meta: options?.meta ?? {},
                },
            ],
        }).catch(() => {
            // Telemetry is best-effort and must not block the CMS UI.
        });
    }, [activeSection, activeTab, builderPreviewMode, page.url, pageEditorMode, site.id]);
    const templatePageHtmlFileBySlug = useMemo(() => {
        const map = new Map<string, string>();
        const rawPages = Array.isArray(templateBlueprint?.default_pages) ? templateBlueprint.default_pages : [];

        rawPages.forEach((page) => {
            if (!isRecord(page)) {
                return;
            }

            const templateFile = typeof page.template_file === 'string'
                ? page.template_file.trim().replace(/^\/+/, '')
                : '';
            if (templateFile === '') {
                return;
            }

            const rawSlug = typeof page.slug === 'string'
                ? page.slug.trim()
                : (typeof page.key === 'string' ? page.key.trim() : '');
            const normalizedSlug = slugify(rawSlug);
            const resolvedSlug = normalizedSlug === '' || normalizedSlug === 'index' ? 'home' : normalizedSlug;

            map.set(resolvedSlug, templateFile);
        });

        return map;
    }, [templateBlueprint?.default_pages]);
    const isHomePageSelected = useMemo(() => {
        const slug = selectedPageDetail?.page.slug?.trim().toLowerCase();
        return slug === 'home';
    }, [selectedPageDetail?.page.slug]);

    const publicDomain = useMemo(() => {
        return site.primary_domain ?? site.subdomain;
    }, [site.primary_domain, site.subdomain]);
    const selectedPageEditorSlug = useMemo(() => {
        const preferredSlug = pageMetaForm.slug.trim();
        const fallbackSlug = selectedPageSummary?.slug?.trim() ?? 'home';
        const normalized = slugify(preferredSlug !== '' ? preferredSlug : fallbackSlug);

        return normalized || 'home';
    }, [pageMetaForm.slug, selectedPageSummary?.slug]);
    const selectedPageEditorPath = useMemo(() => {
        return normalizeCmsUrlPath(selectedPageEditorSlug === 'home' ? '/' : `/${selectedPageEditorSlug}`);
    }, [selectedPageEditorSlug]);
    const selectedPageEditorPreviewUrl = useMemo(() => {
        const templateSlug = templateBlueprint?.template_slug?.trim();
        if (!templateSlug) {
            return null;
        }

        const slug = selectedPageEditorSlug || 'home';
        const previewFile = templatePageHtmlFileBySlug.get(slug) ?? 'index.html';
        const query = new URLSearchParams({
            site: site.id,
            slug,
            draft: '1',
            live_design: '1',
        });

        return `/template-demos/${templateSlug}/${previewFile}?${query.toString()}`;
    }, [selectedPageEditorSlug, site.id, templateBlueprint?.template_slug, templatePageHtmlFileBySlug]);
    const selectedPageEditorLiveUrl = useMemo(() => {
        if (!publicDomain) {
            return null;
        }

        return `https://${publicDomain}${selectedPageEditorPath}`;
    }, [publicDomain, selectedPageEditorPath]);
    const currentCustomDomain = useMemo(() => {
        const candidate = typeof project.custom_domain === 'string' ? project.custom_domain.trim() : '';
        if (candidate !== '') {
            return candidate;
        }

        if (site.primary_domain && site.subdomain && site.primary_domain !== site.subdomain) {
            return site.primary_domain;
        }

        return null;
    }, [project.custom_domain, site.primary_domain, site.subdomain]);
    const platformSubdomainHost = useMemo(() => {
        const siteSubdomain = typeof site.subdomain === 'string' ? site.subdomain.trim() : '';
        if (siteSubdomain !== '') {
            return siteSubdomain;
        }

        const projectSubdomain = typeof project.subdomain === 'string' ? project.subdomain.trim() : '';
        if (!projectSubdomain) {
            return null;
        }

        const baseDomain = customDomainConfig?.baseDomain?.trim();
        if (!baseDomain) {
            return projectSubdomain;
        }

        return `${projectSubdomain}.${baseDomain}`;
    }, [customDomainConfig?.baseDomain, project.subdomain, site.subdomain]);
    const customDomainVerificationRecords = useMemo(() => {
        if (!verificationInstructions) {
            return [];
        }

        const rawRecords = Array.isArray(verificationInstructions.records) && verificationInstructions.records.length > 0
            ? verificationInstructions.records
            : [{
                record_type: verificationInstructions.record_type,
                host: verificationInstructions.host,
                value: verificationInstructions.value,
            }];

        return rawRecords.filter((record) => {
            const recordType = typeof record.record_type === 'string' ? record.record_type.trim() : '';
            const host = typeof record.host === 'string' ? record.host.trim() : '';
            const value = typeof record.value === 'string' ? record.value.trim() : '';

            return recordType !== '' || host !== '' || value !== '';
        });
    }, [verificationInstructions]);
    const customDomainStatusBadge = useMemo(() => {
        if (!currentCustomDomain) {
            return {
                label: t('Not connected'),
                variant: 'outline' as const,
            };
        }

        const sslStatus = (project.custom_domain_ssl_status ?? '').toLowerCase();
        if (sslStatus === 'active') {
            return { label: t('Active'), variant: 'default' as const };
        }

        if (project.custom_domain_verified) {
            if (sslStatus === 'pending') {
                return { label: t('SSL Provisioning'), variant: 'secondary' as const };
            }

            if (sslStatus === 'failed') {
                return { label: t('SSL Failed'), variant: 'destructive' as const };
            }

            return { label: t('Verified'), variant: 'secondary' as const };
        }

        return { label: t('Pending Verification'), variant: 'outline' as const };
    }, [currentCustomDomain, project.custom_domain_ssl_status, project.custom_domain_verified, t]);

    const moduleMap = useMemo(() => {
        const map = new Map<string, ModuleRegistryItem>();
        modules.forEach((item) => {
            map.set(item.key, item);
        });

        return map;
    }, [modules]);

    const isModuleAvailable = useCallback((moduleKey: string) => {
        if (isAdminUser) {
            return true;
        }

        if (moduleMap.size === 0) {
            return true;
        }

        return Boolean(moduleMap.get(moduleKey)?.available);
    }, [isAdminUser, moduleMap]);
    const isModuleProjectTypeAllowed = useCallback((moduleKey: string) => {
        if (moduleMap.size === 0) {
            return true;
        }

        const item = moduleMap.get(moduleKey);
        if (!item) {
            return true;
        }

        return item.project_type_allowed !== false;
    }, [moduleMap]);
    const isBuilderSectionAllowedByProjectTypeAvailabilityMatrix = useCallback((normalizedKey: string) => {
        if (normalizedKey === '') {
            return true;
        }

        for (const rule of builderSectionAvailabilityMatrix) {
            if (!rule.sectionKeys.has(normalizedKey)) {
                continue;
            }

            for (const moduleKey of rule.requiredModules) {
                if (!isModuleProjectTypeAllowed(moduleKey)) {
                    return false;
                }
                if (!isModuleAvailable(moduleKey)) {
                    return false;
                }
            }
        }

        return true;
    }, [builderSectionAvailabilityMatrix, isModuleAvailable, isModuleProjectTypeAllowed]);

    const canUseMediaModule = useMemo(() => isModuleAvailable(MODULE_MEDIA_LIBRARY), [isModuleAvailable]);
    const customFonts = useMemo(() => {
        return availableFonts.filter((font) => font.source_type === 'custom');
    }, [availableFonts]);
    const availableFontsByKey = useMemo(() => {
        const map = new Map<string, TypographyFontOption>();
        availableFonts.forEach((font) => {
            const key = typeof font.key === 'string' ? font.key.trim().toLowerCase() : '';
            if (key !== '') {
                map.set(key, font);
            }
        });

        return map;
    }, [availableFonts]);
    const moduleSummary = useMemo(() => {
        const total = modules.length;
        const available = modules.filter((item) => item.available).length;

        return {
            total,
            available,
        };
    }, [modules]);
