            const restaurantItems = filteredSectionLibrary.filter((item) => syntheticRestaurantSectionKeySet.has(normalizeSectionTypeKey(item.key)));
            const hotelItems = filteredSectionLibrary.filter((item) => syntheticHotelSectionKeySet.has(normalizeSectionTypeKey(item.key)));
