                    header.setAttribute('data-webu-role', 'form-wrapper-header');
                    const title = doc.createElement('h3');
                    title.setAttribute('data-webu-field', 'title');
                    title.textContent = t('Checkout Form');
                    const subtitle = doc.createElement('p');
                    subtitle.setAttribute('data-webu-field', 'subtitle');
                    subtitle.textContent = t('Collect customer details before payment.');
                    header.append(title, subtitle);
                    box.appendChild(header);

                    const validation = doc.createElement('div');
                    validation.setAttribute('data-webu-role', 'form-wrapper-validation');
                    const validationBadge = doc.createElement('span');
                    validationBadge.setAttribute('data-webu-role', 'form-wrapper-validation-badge');
                    validationBadge.textContent = '!';
                    const validationMessage = doc.createElement('div');
                    validationMessage.setAttribute('data-webu-role', 'form-wrapper-validation-message');
                    validationMessage.setAttribute('data-webu-field', 'validation_message');
                    validationMessage.textContent = '';
                    validation.append(validationBadge, validationMessage);
                    box.appendChild(validation);

                    const helper = doc.createElement('div');
                    helper.setAttribute('data-webu-role', 'field-helper');
                    helper.setAttribute('data-webu-field', 'helper_text');
