                const appendSimpleEcomScaffold = (options: {
                    markerAttribute: string;
                    markerTag?: 'div' | 'form' | 'a';
                    titleText: string;
                    subtitleText: string;
                    includeLoading?: boolean;
                    includeError?: boolean;
                    includeEmpty?: boolean;
                    includeUnauthorized?: boolean;
                    includeSkeleton?: boolean;
                    loadingTitle?: string;
                    errorTitle?: string;
                    errorDescription?: string;
                    emptyTitle?: string;
                    emptyDescription?: string;
                    unauthorizedTitle?: string;
                    unauthorizedDescription?: string;
                    unauthorizedCtaLabel?: string;
                    unauthorizedCtaUrl?: string;
                    buildData?: (dataWrap: HTMLElement) => void;
                }) => {
                    appendEcomHeader(options.titleText, options.subtitleText);

                    const markerTag = options.markerTag ?? 'div';
                    const dataWrap = doc.createElement(markerTag) as HTMLElement;
                    dataWrap.setAttribute('data-webu-role', 'ecom-component-data');
                    dataWrap.setAttribute(options.markerAttribute, '');
                    if (markerTag === 'form') {
                        (dataWrap as HTMLFormElement).setAttribute('action', '#');
                    }
                    if (markerTag === 'a') {
                        (dataWrap as HTMLAnchorElement).href = '#';
                    }
                    placeholder.appendChild(dataWrap);
                    options.buildData?.(dataWrap);

                    if (options.includeSkeleton) {
                        const skeleton = doc.createElement('div');
                        skeleton.setAttribute('data-webu-role', 'ecom-skeleton-grid');
                        placeholder.appendChild(skeleton);
                    }
                    if (options.includeLoading) {
                        appendEcomStateBox(
                            'loading',
                            'loading_title',
                            options.loadingTitle ?? t('Loading component...'),
                        );
                    }
                    if (options.includeError) {
                        appendEcomStateBox(
                            'error',
                            'error_title',
                            options.errorTitle ?? t('Component unavailable'),
                            options.errorDescription ? 'error_description' : undefined,
                            options.errorDescription,
                        );
                    }
                    if (options.includeEmpty) {
                        appendEcomStateBox(
                            'empty',
                            'empty_title',
                            options.emptyTitle ?? t('No data'),
                            options.emptyDescription ? 'empty_description' : undefined,
                            options.emptyDescription,
                        );
                    }
                    if (options.includeUnauthorized) {
                        appendEcomStateBox(
                            'unauthorized',
                            'unauthorized_title',
                            options.unauthorizedTitle ?? t('Login required'),
                            options.unauthorizedDescription ? 'unauthorized_description' : undefined,
                            options.unauthorizedDescription,
                            options.unauthorizedCtaLabel ? 'unauthorized_cta_label' : undefined,
                            options.unauthorizedCtaLabel,
                            options.unauthorizedCtaUrl ? 'unauthorized_cta_url' : undefined,
                            options.unauthorizedCtaUrl,
                        );
                    }
                };

