            const carouselVariant = /^design-\d+$/.test(rawVariant) ? rawVariant : 'design-01';
            const isEditorialVariant = carouselVariant === 'design-01' || carouselVariant === 'design-02';
            const titleText = typeof effectiveProps.title === 'string' ? effectiveProps.title.trim() : '';
            const subtitleText = typeof effectiveProps.subtitle === 'string' ? effectiveProps.subtitle.trim() : '';
            const hasHeaderText = titleText !== '' || subtitleText !== '';
