            const input = container.querySelector<HTMLInputElement>('[data-webu-role="ecom-search-input"]');
            const button = container.querySelector<HTMLElement>('[data-webu-role="ecom-search-button"]');
            const dropdown = container.querySelector<HTMLElement>('[data-webu-role="ecom-search-dropdown"]');
            const emptyNode = container.querySelector<HTMLElement>('[data-webu-role="ecom-state-box"][data-webu-role-state="empty"]');
