            const stockStatus = stockStatusRaw === '' ? 'in_stock' : stockStatusRaw;
            const stockQty = Math.max(0, parseIntProp(effectiveProps.stock_qty_preview, 12));
            const qtyMin = Math.max(1, parseIntProp(effectiveProps.qty_min, 1));
            const qtyMax = Math.max(qtyMin, parseIntProp(effectiveProps.qty_max, Math.max(qtyMin, 10)));
            const qtyDefault = Math.min(qtyMax, Math.max(qtyMin, parseIntProp(effectiveProps.qty_default, qtyMin)));

            const priceColor = readColor(effectiveProps.price_color, '#111827');
            const accentColor = readColor(effectiveProps.accent_color, '#2563eb');
