                if (total) {
                    total.style.display = showTotal ? '' : 'none';
                }
                if (dataLink) {
                    dataLink.style.borderColor = readColor(effectiveProps.border_color, '#e5e7eb');
                    dataLink.style.backgroundColor = readColor(effectiveProps.background_color, '#ffffff');
                }
