                        row.setAttribute('data-webu-role', 'ecom-security-session-row');
                        row.style.display = 'grid';
                        row.style.gridTemplateColumns = '1fr auto';
                        row.style.gap = '8px';
                        row.style.alignItems = 'center';
                        row.style.border = '1px solid #e5e7eb';
                        row.style.borderRadius = '8px';
                        row.style.padding = '8px 10px';
                        const label = container.ownerDocument.createElement('div');
                        label.textContent = i === 0 ? t('Current browser · Tbilisi') : `${t('Device')} ${i + 1}`;
                        label.style.fontSize = '12px';
                        const status = container.ownerDocument.createElement('span');
                        status.textContent = i === 0 ? t('Active now') : t('Recent');
