                    devicesCta.style.width = 'fit-content';
                    devicesCta.style.padding = '0 10px';
                    devicesCta.style.border = `1px solid ${accentColor}`;
                    devicesCta.style.borderRadius = '8px';
                    devicesCta.style.background = '#ffffff';
                    devicesCta.style.color = accentColor;
                    devicesCta.textContent = typeof effectiveProps.devices_cta_label === 'string' && effectiveProps.devices_cta_label.trim() !== ''
                        ? effectiveProps.devices_cta_label.trim()
                        : t('Manage Devices');
