    const loadPages = useCallback(async (preferredPageId: number | null = null) => {
        setIsPagesLoading(true);

        try {
            const response = await axios.get<{ site_id: string; pages: PageSummary[] }>(`/panel/sites/${site.id}/pages`);
            const nextPages = response.data.pages ?? [];
            setPages(nextPages);

            setSelectedPageId((current) => {
                const preferred = preferredPageId !== null && nextPages.some((item) => item.id === preferredPageId)
                    ? preferredPageId
                    : null;

                if (preferred !== null) {
                    return preferred;
                }

                if (current !== null && nextPages.some((item) => item.id === current)) {
                    return current;
                }

                const homePage = nextPages.find((item) => item.slug?.trim().toLowerCase() === 'home');
                if (homePage) {
                    return homePage.id;
                }

                return nextPages[0]?.id ?? null;
            });
        } catch (error) {
            toast.error(getApiErrorMessage(error, t('Failed to load pages')));
        } finally {
            setIsPagesLoading(false);
        }
    }, [site.id, t]);

