    const handleCreatePageTemplatePresetChange = useCallback((templateKey: string) => {
        const normalizedKey = templateKey.trim().toLowerCase();
        const preset = availableStorefrontPageTemplatePresetByKey.get(normalizedKey) ?? null;

        setCreatePageForm((prev) => {
            if (!preset) {
                return {
                    ...prev,
                    template_key: '',
                };
            }

            return {
                ...prev,
                template_key: preset.key,
                title: preset.label,
                slug: slugify(preset.slug),
                seo_title: preset.seo_title ?? prev.seo_title,
                seo_description: preset.seo_description ?? prev.seo_description,
            };
        });
    }, [availableStorefrontPageTemplatePresetByKey]);

    const handleCreatePage = async (event: FormEvent<HTMLFormElement>) => {
        event.preventDefault();

        if (!createPageForm.title.trim() || !createPageForm.slug.trim()) {
            toast.error(t('Title and slug are required.'));
            return;
        }

        setIsCreatingPage(true);

        try {
            const selectedTemplatePreset = availableStorefrontPageTemplatePresetByKey.get(createPageForm.template_key.trim().toLowerCase()) ?? null;
            const templateSectionsPayload = selectedTemplatePreset
                ? selectedTemplatePreset.section_blueprints.map((section) => ({
                    type: section.type,
                    props: hydrateSectionDefaultsFromCms(section.type, cloneRecord(section.props)),
                }))
                : [];
            const response = await axios.post<{ page: { id: number } }>(`/panel/sites/${site.id}/pages`, {
                title: createPageForm.title.trim(),
                slug: createPageForm.slug.trim(),
                seo_title: createPageForm.seo_title.trim() || null,
                seo_description: createPageForm.seo_description.trim() || null,
                content_json: builderPageModelToContentJson(buildBuilderPageModelFromContentJson({
                    editor_mode: 'builder',
                    text_editor_html: '',
                    sections: templateSectionsPayload,
                }, {
                    createLocalId: () => nextSectionLocalId(),
                    normalizeProps: (sectionType, props) => normalizeSectionPropsStyle(
                        hydrateSectionDefaultsFromCms(sectionType, props)
                    ) as Record<string, unknown>,
                })),
            });

            const createdPageId = response.data.page?.id ?? null;

            toast.success(t('Page created successfully'));
            setCreatePageForm({
                template_key: '',
                title: '',
                slug: '',
                seo_title: '',
                seo_description: '',
            });
            setIsCreatePageDialogOpen(false);

            await loadPages(createdPageId);
            setActiveSection('cms-entries');
            setActiveTab('editor');
        } catch (error) {
            toast.error(getApiErrorMessage(error, t('Failed to create page')));
        } finally {
            setIsCreatingPage(false);
        }
    };

    const resetBlogPostForm = useCallback(() => {
        setBlogPostForm({
            title: '',
            slug: '',
            excerpt: '',
            content: '',
            status: 'draft',
            coverMediaId: null,
            coverMediaUrl: '',
        });
    }, []);

    const openCreateBlogPostDialog = useCallback(() => {
        setEditingBlogPostId(null);
        resetBlogPostForm();
        setIsBlogPostDialogOpen(true);
    }, [resetBlogPostForm]);

