            isStructurePanelCollapsed,
            selectedPage: selectedPageBridgeIdentity,
            stateVersion: embeddedBuilderStateVersion,
            structureHash: embeddedBuilderStructureHash,
            revisionId: embeddedBuilderRevisionId,
            revisionVersion: embeddedBuilderRevisionVersion,
            selectedSectionLocalId,
            selectedSectionDraft,
            selectedFixedSectionKey,
            selectedBuilderTarget,
            sectionsDraft,
            builderSectionLibrary,
            sectionDisplayLabelByKey,
            t,
