                                                                        onAddSectionInsideAtPath={handleAddSectionInsideAtPath}
                                                                        addInsideSectionOptions={addInsideSectionOptions}
                                                                        layoutPrimitiveKeys={layoutPrimitiveSectionKeys}
                                                                        showAddInside={isLayoutPrimitive}
